class Solution:
    def longestCommonPrefix(self, arr1: List[int], arr2: List[int]) -> int:
        # Build trie for arr1
        trie = {}
        for num in arr1:
            node = trie
            for ch in str(num):
                if ch not in node:
                    node[ch] = {}
                node = node[ch]

        # Check prefixes in arr2 against trie
        max_len = 0
        for num in arr2:
            node = trie
            for i, ch in enumerate(str(num)):
                if ch not in node:
                    break
                node = node[ch]
                max_len = max(max_len, i + 1)

        return max_len
